// Java 8 Solution using Stream
import java.util.*;
import java.util.stream.*;

public class Solution {
    public static int findSecondHighest(int[] arr) {
        if (arr.length < 2) return -1;

        return Arrays.stream(arr)
            .distinct()
            .boxed()
            .sorted(Comparator.reverseOrder())
            .skip(1)
            .findFirst()
            .orElse(-1);
    }
}

// Without Java 8 Solution
public class Solution {
    public static int findSecondHighest(int[] arr) {
        if (arr.length < 2) return -1;

        int first = Integer.MIN_VALUE;
        int second = Integer.MIN_VALUE;

        for (int i = 0; i < arr.length; i++) {
            if (arr[i] > first) {
                second = first;
                first = arr[i];
            } else if (arr[i] > second && arr[i] != first) {
                second = arr[i];
            }
        }

        return second == Integer.MIN_VALUE ? -1 : second;
    }

    public static void main(String[] args) {
        int[] arr = {12, 35, 1, 10, 34, 1};
        System.out.println("Second Highest: " + findSecondHighest(arr));
    }
}

// Alternative without Java 8 (handling duplicates)
public class Solution {
    public static int findSecondHighest(int[] arr) {
        if (arr == null || arr.length < 2) {
            throw new IllegalArgumentException("Array must have at least 2 elements");
        }

        int max1 = arr[0];
        int max2 = Integer.MIN_VALUE;

        for (int i = 1; i < arr.length; i++) {
            if (arr[i] > max1) {
                max2 = max1;
                max1 = arr[i];
            } else if (arr[i] > max2 && arr[i] != max1) {
                max2 = arr[i];
            }
        }

        if (max2 == Integer.MIN_VALUE) {
            throw new RuntimeException("No second highest element found");
        }

        return max2;
    }
}

